import React from "react";
import { Link, useLocation } from "react-router-dom";
import "./Bookingconfi"
export default function BookingConfirmation() {
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const stayName = queryParams.get("name");

  const successImage =
    "https://images.pexels.com/photos/3184465/pexels-photo-3184465.jpeg";

  return (
    <div style={{ textAlign: "center", padding: "50px" }}>
      <div
        style={{
          background: "#fff",
          borderRadius: "16px",
          boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
          padding: "40px",
          display: "inline-block",
          maxWidth: "600px",
        }}
      >
        <img
          src={successImage}
          alt="Booking Confirmed"
          style={{
            width: "100%",
            height: "250px",
            objectFit: "cover",
            borderRadius: "12px",
            marginBottom: "20px",
          }}
        />
        <h1>🎉 Booking Confirmed!</h1>
        {stayName ? (
          <p style={{ fontSize: "18px" }}>
            Your booking for <strong>{stayName}</strong> has been confirmed. 🏡
          </p>
        ) : (
          <p>Your stay has been successfully booked!</p>
        )}
        <p>Thank you for choosing our Airbnb Clone.</p>
        <Link to="/">
          <button
            style={{
              background: "#ff385c",
              color: "#fff",
              border: "none",
              padding: "10px 20px",
              borderRadius: "8px",
              cursor: "pointer",
            }}
          >
            Back to Home
          </button>
        </Link>
      </div>
    </div>
  );
}
